local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "Die Nachricht ist leer.", no_links = "Links sind nicht erlaubt.",
    too_long = "Die Nachricht ist zu lang (maximal 500 Zeichen).", rate_limited = "Du hast das Limit von 3 Nachrichten erreicht. Bitte versuche es später erneut.",
    busy = "Der Server ist ausgelastet. Bitte versuche es erneut.", banned = "Du darfst kein Feedback senden.",
    discord_error = "Senden fehlgeschlagen. Bitte versuche es erneut.", network = "Netzwerkfehler.",
    no_request = "Dein Executor kann keine Anfragen senden.", bad_response = "Der Server hat eine unerwartete Antwort zurückgegeben.",
    unreachable = "Dein Executor erreicht den Server nicht (TLS-Fehler). Bitte probiere einen anderen Executor.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Vorschläge / Hilfe", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Typ", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Nachricht", Placeholder = "Nachricht eingeben (maximal 500 Zeichen, keine Links)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Bitte warte %d Sekunden, bevor du erneut sendest.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "Die Nachricht ist leer."); return end
        if #msg > 500 then safeSet(fbStatus, "Die Nachricht ist zu lang (maximal 500 Zeichen)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Links sind nicht erlaubt."); return
        end
        safeSet(fbStatus, "Wird gesendet...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Gesendet. Danke!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Dein Feedback wurde gesendet. Danke!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Senden fehlgeschlagen: " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("Maximal 3 Nachrichten pro Stunde. Keine Links oder Erwähnungen.", true)

