task.spawn(function()
    safeSet(statusLabel, "Wird authentifiziert...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Status: Fehlgeschlagen")
        Library:Notify({Title="COMBOWICK", Description="Die Sitzungsprüfung ist fehlgeschlagen.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Spiel deaktiviert")
            safeSet(hintLabel, "Die kostenlose Version ist hier nicht verfügbar. Hol dir einen Key.")
            Library:Notify({Title="COMBOWICK", Description="Die kostenlose Version ist für dieses Spiel deaktiviert. Bitte nutze einen Key.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Status: Fehlgeschlagen")
        else
            safeSet(statusLabel, "Status: Authentifiziert")
            Library:Notify({Title="COMBOWICK", Description="Du bist authentifiziert.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Verbleibende Zeit: %s", fmt))
                    safeSet(lSession, string.format("Sitzungszeit: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "Die Sitzung ist abgelaufen.")
                safeSet(lSession, "Sitzungszeit: abgelaufen")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "In Abklingzeit")
        safeSet(hintLabel, "Hol dir einen 11-Stunden-Key oder warte, bis die Abklingzeit endet.")
        Library:Notify({Title="COMBOWICK", Description="Du bist in der Abklingzeit. Hol dir einen Key, um die Wartezeit zu überspringen.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Abklingzeit: %s", fmt))
                safeSet(lCooldown, string.format("Abklingzeit: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Die Abklingzeit ist beendet.")
            safeSet(lCooldown, "Abklingzeit: beendet")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Die Abklingzeit ist beendet. Wird neu geladen...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Zu viele Anfragen")
        safeSet(hintLabel, "Zu viele Anfragen. Bitte warte.")
        Library:Notify({Title="COMBOWICK", Description="Zu viele Anfragen. Bitte warte einen Moment.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Erneut versuchen in %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Wird neu geladen...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Dienst pausiert")
        safeSet(hintLabel, "COMBOWICK ist vorübergehend offline.")
        Library:Notify({Title="COMBOWICK", Description="Der Dienst ist derzeit deaktiviert. Bitte versuche es später erneut.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Gesperrt")
        Library:Notify({Title="COMBOWICK", Description="Du bist gesperrt.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Spiel nicht unterstützt")
        safeSet(hintLabel, "Dieses Spiel wird noch nicht unterstützt. Premium-Keys funktionieren weiterhin, falls ein Skript verfügbar ist.")
        Library:Notify({Title="COMBOWICK", Description="Dieses Spiel wird noch nicht unterstützt.", Time=6})

    else
        safeSet(statusLabel, "Fehler")
        safeSet(hintLabel, "Server konnte nicht erreicht werden. Bitte starte das Skript erneut.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Ein unbekannter Fehler ist aufgetreten."), Time=5})
    end
end)

